for i,venue in enumerate(vns):
    print(f'  処理中: {venue}')
    venue_df = df_all[df_all['venue_name']==venue]
    active_class = ' active' if i==0 else ''
    html_parts.append(f'<div class="venue-content{active_class}" id="{venue}">')
    
    for race_num in sorted(venue_df['race_no'].unique()):
        race_df = venue_df[venue_df['race_no']==race_num]
        sr = calc(race_df, VENUE_PATTERNS[venue], RATE_TABLES[venue])
        if not sr: continue
        lbl = sr[0]['third_label']
        html_parts.append(f'<div class="race-card"><h2 class="race-title">{race_num}R（平均: {sr[0]["avg"]:.2f}）</h2><table><thead><tr>')
        html_parts.append(f'<th>艇番</th><th>展示</th><th>1周</th><th>{lbl}</th><th>シンsum</th><th>平均との差</th><th>1着率</th><th>2着率</th><th>3着率</th><th>3連対率</th></tr></thead><tbody>')
        for r in sr:
            dc='positive' if r['diff']>0 else 'negative' if r['diff']<0 else ''
            ds='+' if r['diff']>0 else ''
            def rc(x): return 'rate-positive' if x>0 else 'rate-negative' if x<0 else 'rate-neutral'
            def rs(x): return f'+{x}' if x>0 else str(x)
            html_parts.append(f'<tr class="boat-{r["number"]}"><td><strong>{r["number"]}号艇</strong></td><td>{r["exhibition"]:.2f}</td><td>{r["one_lap"]:.2f}</td><td>{r["third"]:.2f}</td>')
            html_parts.append(f'<td><strong>{r["shinsum"]:.2f}</strong></td><td class="{dc}"><strong>{ds}{r["diff"]:.2f}</strong></td>')
            html_parts.append(f'<td><span class="rate-box {rc(r["rate_1"])}">{rs(r["rate_1"])}%</span></td>')
            html_parts.append(f'<td><span class="rate-box {rc(r["rate_2"])}">{rs(r["rate_2"])}%</span></td>')
            html_parts.append(f'<td><span class="rate-box {rc(r["rate_3"])}">{rs(r["rate_3"])}%</span></td>')
            html_parts.append(f'<td><span class="rate-box {rc(r["rate_renntai"])}">{rs(r["rate_renntai"])}%</span></td></tr>')
        html_parts.append('</tbody></table></div>')
